const regLow = msg.payload[0];
const regHigh = msg.payload[1];

const buf = Buffer.alloc(4);
buf.writeUInt16BE(regHigh, 0);
buf.writeUInt16BE(regLow, 2);

msg.payload = buf.readFloatBE(0);

// Store in global vibit
let vibit = global.get('vibit') || {};
vibit.sensor_1 = msg.payload;
global.set('vibit', vibit);

return msg;

