const v = global.get('vibit') || {};

const mappedData = {
  status: {
    green: v.lead_status === 1,
    yellow: v.lead_status === 0,
    red: false,
    cycle_start: (v.calculated_rpm || 0) > 0
  },
  spindle: {
    speed: v.calculated_rpm || 0,
    temperature: v.sensor_1 || 0,
    vibration: v.x_rms_acceleration || 0
  },
  tool: {
    number: 1,
    temperature: v.sensor_1 || 0,
    vibration: v.y_rms_acceleration || 0,
    reboot_count: v.reboot_count || 0
  },
  axes: {
    x: {
      rms_accel:    v.x_rms_acceleration || 0,
      rms_velocity: v.x_rms_velocity || 0,
      peak_accel:   v.x_peak_acceleration || 0,
      peak_velocity: v.x_peak_velocity || 0
    },
    y: {
      rms_accel:    v.y_rms_acceleration || 0,
      rms_velocity: v.y_rms_velocity || 0,
      peak_accel:   v.y_peak_acceleration || 0,
      peak_velocity: v.y_peak_velocity || 0
    },
    z: {
      rms_accel:    v.z_rms_acceleration || 0,
      rms_velocity: v.z_rms_velocity || 0,
      peak_accel:   v.z_peak_acceleration || 0,
      peak_velocity: v.z_peak_velocity || 0
    }
  }
};

msg.payload = mappedData;
return msg;
